"use strict";

const Anthropic = require("@anthropic-ai/sdk");
const { handleCorsPreflight } = require("../_lib/cors");

/**
 * Vercel serverless function: POST /api/onboarding/generate-plan-full
 *
 * Returns { plan: TrainingPlanV2 } — full plan generated by Claude (Option A).
 */
module.exports = async function handler(req, res) {
  if (handleCorsPreflight(req, res)) return;

  res.setHeader("Content-Type", "application/json");
  if (req.method !== "POST") {
    return res.status(405).json({ error: "Method Not Allowed" });
  }

  try {
    const { profile } = req.body ?? {};
    if (!profile) return res.status(400).json({ error: "profile required" });

    const key = process.env.ANTHROPIC_API_KEY?.trim();
    if (!key) return res.status(500).json({ error: "ANTHROPIC_API_KEY missing" });

    console.log("[API] POST /onboarding/generate-plan-full called");

    const client = new Anthropic({ apiKey: key });

    const systemPrompt = buildSystemPrompt();
    const userMessage = buildUserMessage(profile);

    const message = await client.messages.create({
      model: "claude-sonnet-4-6",
      max_tokens: 4500,
      system: systemPrompt,
      messages: [{ role: "user", content: userMessage }],
    });

    const text = message.content
      .filter((b) => b.type === "text")
      .map((b) => b.text)
      .join("");

    const clean = text.replace(/```json|```/g, "").trim();
    const parsed = JSON.parse(clean);
    const plan = rebuildPlanFromWorkouts(normalizeWorkouts(parsed, profile));

    return res.status(200).json({ plan });
  } catch (err) {
    console.error(
      "[api/onboarding/generate-plan-full] error:",
      typeof err?.message === "string" ? err.message : "unknown",
    );
    return res.status(500).json({ error: "Plan generation failed", detail: err?.message });
  }
};

function buildSystemPrompt() {
  return `Du bist ein erfahrener Marathontrainer. Generiere einen vollständigen, periodisierten Marathontrainingsplan als JSON.

Gib NUR gültiges JSON zurück, kein Markdown, keine Erklärungen.

SCHEMA (exakt einhalten):
{
  "version": 2,
  "weeks": [
    { "id": "w1", "label": "Woche 1", "phase": "BASE", "startIso": "YYYY-MM-DD", "totalKm": 40 }
  ],
  "workouts": [
    {
      "id": "w1-mo", "weekId": "w1", "day": "Mo", "date": "28. Jun",
      "type": "easy", "title": "Lockerer Dauerlauf", "km": 8,
      "description": "GA1-Bereich, Herzfrequenz niedrig halten.", "phase": "BASE"
    }
  ]
}

PHASEN-STRUKTUR (strikt einhalten):
- BASE (erste 30-35% der Wochen): Aerobe Basis, moderate Steigerung, 1-2 Intervall/Tempo-Einheiten pro Woche
- BUILD (mittlere 35-40%): Spezifische Vorbereitung, höheres Volumen, 2-3 Qualitätseinheiten pro Woche  
- PEAK (letzte 10-15% vor Taper): Höchstes Volumen, race-pace Einheiten, Long Runs bis 32-35km
- TAPER (letzte 2-3 Wochen): Volumen STARK reduzieren (-30% Woche 1, -50% Woche 2, -70% Rennwoche), keine langen oder harten Einheiten

VOLUMEN-WELLENSTRUKTUR (PFLICHT):
- Jede 4. Woche ist eine Entlastungswoche mit -25 bis -30% Volumen gegenüber der Vorwoche
- Steigerung nie mehr als 10% pro Woche
- TAPER-Wochen: Long Run maximal 15km in Woche -2, maximal 12km in Woche -1 vor dem Rennen
- Rennwoche: nur leichte Einheiten bis Di/Mi, dann Ruhe, Renntag So/Sa

WOCHENTAG-VARIANZ (PFLICHT — keine Woche darf identisch zur Vorwoche sein):
Jede Woche muss diese Struktur haben (angepasst an Präferenzen):
- 1x Long Run (So oder Sa bevorzugt)
- 1x Intervall oder Tempoeinheit (Di oder Mi)  
- 1x Tempo oder Schwellenlauf (Do)
- 2-3x Easy Run (variierende Distanzen)
- 1-2x Ruhetag
- Bike/Kraft-Einheiten laut Präferenzen einbauen

TAPER-QUALITÄT:
- Taper ≠ nur Easy Runs. Kurze, scharfe Einheiten beibehalten (1-2x kurze Intervalle pro Woche)
- Kein Long Run über 15km in den letzten 3 Wochen vor dem Rennen
- Gesamt-Wochenvolumen im Taper: 60%, 50%, 30% des Peak-Volumens

EINHEITEN-ROTATION (PFLICHT):
Ein guter Trainingsplan fühlt sich nicht repetitiv an. Konkret:
- Intervalleinheiten variieren: Woche 1 = 6x1km, Woche 3 = 8x800m, Woche 5 = 5x2km, Woche 7 = 10x400m
- Tempoläufe variieren: mal 20min Tempo, mal 2x15min, mal Fahrtspiel, mal Progressionslauf
- Long Runs variieren: mal ruhig gleichmäßig, mal letztes Drittel schneller, mal mit race-pace Einschüben
- Easy Runs variieren in Distanz: nicht jede Woche 8km — mal 6km, mal 10km, mal 12km
- Beschreibungen (description-Feld) müssen konkrete Anweisungen enthalten: Pace-Bereich, Herzfrequenzzone, oder genaue Struktur der Einheit (z.B. "10 Min einspielen, 6x1km bei 4:30/km mit 90 Sek Pause, 10 Min auslaufen")
- Wochentitel NIEMALS mit Wochennummer ("W3", "Woche 4", "W14" etc.) — nur beschreibende Namen

ALLGEMEINE REGELN:
- Alle 7 Wochentage als workouts (Mo-So), kein Tag auslassen
- day: Mo, Di, Mi, Do, Fr, Sa, So
- date: "28. Jun" Format (kein Jahr)
- startIso: ISO-Datum des Montags der jeweiligen Woche
- type: easy | tempo | interval | long | race | rest | bike | strength
- id Workouts: "w{n}-mo", "w{n}-di" etc.
- id Weeks: "w1", "w2" etc.
- Renntag: type "race", km = Renndistanz, am Renndatum
- Ruhetage: type "rest", km: 0, description: "Aktive Erholung oder vollständige Ruhe."

EINHEITENNAMEN (title-Feld) — abwechslungsreich und beschreibend, NIEMALS generisch wie "easy W3" oder "long run W12":

Beispiele für gute Titel:
- easy: "Lockerer Dauerlauf", "Regenerationseinheit", "GA1-Lauf", "Aktive Erholung", "Ruhiger Ausdauerlauf"
- tempo: "Tempodauerlauf", "Schwellenlauf", "GA2-Einheit", "Fahrtspiel", "Progressionslauf", "Race-Pace Einheit"
- interval: "Intervalltraining 1km", "400m-Wiederholungen", "VO2max-Einheit", "Bergsprints", "1000m-Intervalle", "Bahntraining"
- long: "Langer Ausdauerlauf", "Marathon-Long-Run", "Progressiver Langer Lauf", "Back-to-back Long Run", "Distanzlauf mit race-pace Abschluss"
- rest: "Ruhetag", "Aktive Regeneration", "Mobilität & Dehnen"
- bike: "Rennrad-Einheit", "Aktive Erholung Rad", "Cycling Cross-Training"
- strength: "Krafttraining", "Laufkraft & Stabilität", "Core & Athletik"

Regeln:
- Jeden Titel individuell formulieren — keine Woche darf dieselben Titel wie die Vorwoche haben
- Titel darf KEINE Wochennummer enthalten ("W3", "Woche 4" etc. sind verboten)
- Titel soll die Einheit beschreiben, nicht nummerieren
- description-Feld: 1-2 konkrete Sätze mit Pace-Angabe oder Herzfrequenzzone`;
}

function buildUserMessage(profile) {
  const prefs = profile.userPreferences ?? [];
  const prefsText = prefs.length > 0
    ? prefs.map((p, i) => `${i + 1}. "${p}"`).join("\n")
    : "Keine besonderen Präferenzen.";

  const km = profile.raceDistanceKm ?? 42.2;
  const isTimeGoal = profile.raceGoal !== "finish";
  const goalText = isTimeGoal
    ? `Zeitziel: ${profile.raceTargetTime} — baue race-pace Einheiten ab BUILD-Phase ein`
    : "Ziel: Finisher — Fokus auf Ausdauer, nicht Pace";

  const startKm = parseInt(profile.weeklyKmRange) || 40;
  const level = startKm < 30 ? "Einsteiger" : startKm < 50 ? "Fortgeschrittener Hobbyläufer" : startKm < 70 ? "Ambitionierter Läufer" : "Erfahrener Läufer mit hohem Grundniveau";

  return `Du bist ein erfahrener Lauftrainer. Erstelle einen maßgeschneiderten Trainingsplan für diesen Athleten.

ATHLET:
- Renndistanz: ${profile.raceDistanceLabel} (${km}km)
- Niveau: ${level} (aktuell ${profile.weeklyKmRange} km/Woche)
- ${goalText}
- Planstart: ${profile.planStartDate}
- Renndatum: ${profile.raceDate}

PERSÖNLICHE WÜNSCHE DES ATHLETEN (interpretiere diese wie ein echter Coach — nicht als starre Regeln, sondern als Leitlinien die du sinnvoll in den Plan integrierst):
${prefsText}

Als Coach entscheidest du selbst:
- Wie du die Wünsche umsetzt (z.B. "alle 2 Wochen Krafttraining" → du wählst den besten Tag dafür)
- Wo du Kompromisse machst wenn sich Wünsche mit der Trainingslogik beißen
- Welche Woche für welche Einheit am sinnvollsten ist

Erstelle einen Plan der sich wie von einem echten Coach geschrieben anfühlt — mit Logik, Periodisierung und Individualität. Gib NUR das JSON zurück.`;
}

function sportFromSessionType(type) {
  if (type === "bike") return "bike";
  if (type === "swim") return "swim";
  if (type === "strength") return "strength";
  if (type === "rest") return "rest";
  return "run";
}

function startOfIsoWeekMonday(date) {
  const d = new Date(date);
  d.setHours(12, 0, 0, 0);
  const day = d.getDay();
  const offset = (day + 6) % 7;
  d.setDate(d.getDate() - offset);
  return d;
}

const DAY_OFFSET = { Mo: 0, Di: 1, Mi: 2, Do: 3, Fr: 4, Sa: 5, So: 6 };
const GERMAN_MONTHS = {
  jan: 0,
  feb: 1,
  mär: 2,
  mar: 2,
  apr: 3,
  mai: 4,
  jun: 5,
  jul: 6,
  aug: 7,
  sep: 8,
  okt: 9,
  oct: 9,
  nov: 10,
  dez: 11,
  dec: 11,
};

function addDaysIso(startIso, days) {
  const d = new Date(`${startIso}T12:00:00`);
  d.setDate(d.getDate() + days);
  return d.toISOString();
}

function parseGermanDateLabel(label, fallbackYear) {
  const match = String(label)
    .trim()
    .match(/^(\d{1,2})\.\s*([A-Za-zäöüÄÖÜ]+)/);
  if (!match) return null;
  const day = Number(match[1]);
  const monthKey = match[2].toLowerCase().replace(/\./g, "");
  const month = GERMAN_MONTHS[monthKey.slice(0, 3)];
  if (!Number.isFinite(day) || month == null) return null;
  const year = Number(fallbackYear) || new Date().getFullYear();
  const d = new Date(Date.UTC(year, month, day, 12, 0, 0));
  return Number.isFinite(d.getTime()) ? d.toISOString() : null;
}

function resolveWorkoutDateIso(w, weeksById, profile) {
  if (w.dateIso && Number.isFinite(new Date(w.dateIso).getTime())) {
    return w.dateIso.includes("T") ? w.dateIso : `${w.dateIso.slice(0, 10)}T12:00:00.000Z`;
  }

  if (w.weekId && w.day && weeksById.has(w.weekId)) {
    const offset = DAY_OFFSET[w.day];
    if (offset != null) {
      return addDaysIso(weeksById.get(w.weekId), offset);
    }
  }

  const fallbackYear =
    profile?.planStartDate?.slice(0, 4) ??
    profile?.raceDate?.slice(-4) ??
    new Date().getFullYear();
  if (w.date) {
    const parsed = parseGermanDateLabel(w.date, fallbackYear);
    if (parsed) return parsed;
  }

  return "";
}

function normalizeWorkouts(parsed, profile) {
  const weeksById = new Map();
  if (Array.isArray(parsed?.weeks)) {
    for (const week of parsed.weeks) {
      if (week?.id && week?.startIso) weeksById.set(week.id, week.startIso);
    }
  }

  const raw = Array.isArray(parsed?.workouts) ? parsed.workouts : [];
  return raw.map((w) => ({
    id: String(w.id ?? ""),
    dateIso: resolveWorkoutDateIso(w, weeksById, profile),
    sport: w.sport ?? sportFromSessionType(w.sessionType ?? w.type ?? "easy"),
    sessionType: String(w.sessionType ?? w.type ?? "easy"),
    title: String(w.title ?? ""),
    km: typeof w.km === "number" && Number.isFinite(w.km) ? w.km : 0,
    desc: w.desc ?? w.description ?? null,
    pace: w.pace ?? null,
    structured: w.structured ?? null,
    intensity: w.intensity ?? undefined,
  }));
}

function rebuildPlanFromWorkouts(workouts) {
  const weeksMap = new Map();

  for (const w of workouts) {
    const d = new Date(w.dateIso);
    if (!Number.isFinite(d.getTime())) continue;
    const weekStart = startOfIsoWeekMonday(d).toISOString().slice(0, 10);

    if (!weeksMap.has(weekStart)) {
      weeksMap.set(weekStart, { startIso: weekStart, workouts: [], totalKm: 0 });
    }

    const week = weeksMap.get(weekStart);
    week.workouts.push(w);
    if (w.sport !== "rest" && w.km) week.totalKm += w.km;
  }

  const weeks = Array.from(weeksMap.values()).sort((a, b) =>
    a.startIso.localeCompare(b.startIso),
  );
  for (const week of weeks) {
    week.workouts.sort((a, b) => a.dateIso.localeCompare(b.dateIso));
  }

  return { version: 2, workouts, weeks };
}

module.exports.config = {
  maxDuration: 100,
};
